mapper.select:
SELECT i.id, i.product_id AS productId, p.name AS productName, p.product_code AS productCode, i.batch_no AS batchNo, i.location_id AS locationId, l.location_code AS locationCode, l.zone, i.quantity FROM inventory i LEFT JOIN location l ON i.location_id = l.id LEFT JOIN product p ON i.product_id = p.id
AND l.warehouse_id = #{warehouseId}
AND i.product_id = #{productId}
ORDER BY i.create_time DESC
